import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Link Folders","description":"","frontmatter":{"title":"Link Folders","slug":"link-folders"},"headers":[],"relativePath":"account-hub/link-folders.md","filePath":"account-hub/link-folders.md"}'),l={name:"account-hub/link-folders.md"};function i(s,e,n,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1"><strong>Overview</strong> <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;**Overview**&quot;">​</a></h2><p>With link folders, you can organize your Branch Links by campaign, product line, team, or any structure that matches your workflow. Create folders, add links to them, and associate templates to automatically apply consistent tagging and configuration across all links in that folder.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Short Links are currently the only supported link type for folders. Ad Links are not currently supported.</p></div><h2 id="how-it-works" tabindex="-1"><strong>How it works</strong> <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;**How it works**&quot;">​</a></h2><p>With link folders, you can:</p><ul><li>Create and manage folders to organize your links</li><li>Create links directly within folders (new links automatically belong to their parent folder)</li><li>Move links between folders using the link action menu or edit flow</li><li>Associate templates with folders (all links created in a folder automatically inherit the folder&#39;s template settings)</li><li>Existing Link Collections from legacy Branch are automatically migrated to link folders with their template associations preserved</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>Previously created Link Collections from the legacy Branch experience will now be viewable as folders with their template associations preserved.</p></div><h2 id="get-started" tabindex="-1"><strong>Get started</strong> <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;**Get started**&quot;">​</a></h2><p>Learn how to create and manage folders in our <a href="https://portal.us.document360.io/v1/docs/links-page#folders" target="_blank" rel="noreferrer">Links Page</a> article.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Link folders are only available in the new Branch experience.</p></div>',10)])])}const k=t(l,[["render",i]]);export{u as __pageData,k as default};
